import React from "react";
import { MapContainer, TileLayer, Circle, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";

const MapComponent = ({ buses }) => {
  // Count buses
  const counts = { normal: 0, ghost: 0, anomaly: 0 };
  buses.forEach((b) => counts[b.status]++);

  return (
    <div>
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100vh", width: "100%" }}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="&copy; OpenStreetMap contributors"
        />

        {buses.map((bus) =>
          bus.lat && bus.lon ? (
            <Circle
              key={bus.id}
              center={[bus.lat, bus.lon]}
              radius={100}
              pathOptions={{
                color:
                  bus.status === "normal"
                    ? "green"
                    : bus.status === "ghost"
                    ? "red"
                    : "orange",
              }}
            >
              <Tooltip>{bus.status}</Tooltip>
            </Circle>
          ) : null
        )}
      </MapContainer>

      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          backgroundColor: "white",
          padding: "8px",
          borderRadius: "6px",
          zIndex: 1000,
        }}
      >
        <p>Normal: {counts.normal}</p>
        <p>Ghost: {counts.ghost}</p>
        <p>Anomaly: {counts.anomaly}</p>
      </div>
    </div>
  );
};

export default MapComponent;
